/* 智谱AI GLM-4V-Flash 图片识别 — 国内免费、网络稳定 */
(function () {
  'use strict';

  window.ZhipuOCR = {
    _key: '',
    _model: 'glm-4v-flash',
    _apiUrl: 'https://open.bigmodel.cn/api/paas/v4/chat/completions',

    setKey: function (key) {
      this._key = key.trim();
      try { localStorage.setItem('zhipu_key', this._key); } catch (e) {}
    },

    getKey: function () {
      if (this._key) return this._key;
      try { this._key = localStorage.getItem('zhipu_key') || ''; } catch (e) {}
      return this._key;
    },

    _fileToBase64: function (file) {
      return new Promise(function (resolve, reject) {
        var reader = new FileReader();
        reader.onload = function () {
          resolve(reader.result);
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
      });
    },

    recognize: async function (imageFile, type, onProgress) {
      var key = this.getKey();
      if (!key) throw new Error('请先输入智谱AI API Key');

      if (onProgress) onProgress('正在准备图片...');

      var dataUrl = await this._fileToBase64(imageFile);
      var prompt = type === 'monthly' ? this._monthlyPrompt() : this._dailyPrompt();

      if (onProgress) onProgress('正在调用智谱AI识别（约3-8秒）...');

      var body = {
        model: this._model,
        messages: [{
          role: 'user',
          content: [
            { type: 'text', text: prompt },
            { type: 'image_url', image_url: { url: dataUrl } }
          ]
        }],
        temperature: 0.1,
        max_tokens: 4096
      };

      var res = await fetch(this._apiUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer ' + key
        },
        body: JSON.stringify(body)
      });

      if (!res.ok) {
        var errData = {};
        try { errData = await res.json(); } catch (e) {}
        var msg = (errData.error && errData.error.message) || ('HTTP ' + res.status);
        throw new Error(msg);
      }

      var data = await res.json();
      var text = (data.choices && data.choices[0] && data.choices[0].message)
        ? data.choices[0].message.content
        : '';

      if (!text) throw new Error('AI 未返回内容');

      if (onProgress) onProgress('正在解析结果...');

      return this._parseResponse(text, type);
    },

    _monthlyPrompt: function () {
      return [
        '你是一个精准的数据提取助手。请从这张电费账单截图中提取月度用电数据。',
        '',
        '要求：',
        '1. 每行一条，格式: 月份 电量 电费',
        '2. 月份用数字表示，如 1, 2, ..., 12',
        '3. 电量单位kWh，只写数字不写单位',
        '4. 电费单位元，只写数字不写单位',
        '5. 只提取当月数据，不要年累计数据',
        '6. 不要输出任何其他文字，只输出数据行',
        '7. 如果截图包含年份信息，在最前面加一行: YEAR:XXXX',
        '',
        '示例输出：',
        'YEAR:2026',
        '1 1011 543',
        '2 614 321',
        '3 263 139'
      ].join('\n');
    },

    _dailyPrompt: function () {
      return [
        '你是一个精准的数据提取助手。请从这张每日用电量截图中提取数据。',
        '这可能是日历视图或列表视图的截图。',
        '',
        '要求：',
        '1. 每行一条，格式: 日期 电量',
        '2. 日期格式: MM-DD，如 07-01, 07-02',
        '3. 电量单位kWh，只写数字保留两位小数',
        '4. 只提取每日用电数据，不要合计/日均/总计等统计值',
        '5. 不要输出任何其他文字，只输出数据行',
        '6. 如果能识别年份，在最前面加一行: YEAR:XXXX',
        '7. 日历网格中每个格子里有日期和对应的用电量数字，请仔细识别每个格子',
        '',
        '示例输出：',
        'YEAR:2026',
        '07-01 13.91',
        '07-02 11.34',
        '07-03 5.21'
      ].join('\n');
    },

    _parseResponse: function (text, type) {
      var lines = text.split('\n').map(function (l) { return l.trim(); }).filter(function (l) { return l; });
      var year = null;
      var results = [];

      lines.forEach(function (line) {
        var ym = line.match(/^YEAR[:\s]*(\d{4})/i);
        if (ym) { year = parseInt(ym[1]); return; }

        if (type === 'monthly') {
          var parts = line.split(/[\s\t]+/);
          if (parts.length >= 3) {
            var m = parseInt(parts[0]);
            var k = parseFloat(parts[1]);
            var c = parseFloat(parts[2]);
            if (m >= 1 && m <= 12 && k > 0 && c > 0) {
              results.push({ year: year || new Date().getFullYear(), month: m, kwh: k, cost: c });
            }
          }
        }

        if (type === 'daily') {
          var dm = line.match(/(\d{1,2})-(\d{1,2})[\s\t]+(\d+(?:\.\d+)?)/);
          if (dm) {
            var mo = parseInt(dm[1]);
            var d = parseInt(dm[2]);
            var kwh = parseFloat(dm[3]);
            if (mo >= 1 && mo <= 12 && d >= 1 && d <= 31 && kwh > 0 && kwh < 500) {
              var y = year || new Date().getFullYear();
              results.push({
                date: y + '-' + String(mo).padStart(2, '0') + '-' + String(d).padStart(2, '0'),
                kwh: kwh
              });
            }
          }
        }
      });

      var seen = {};
      results = results.filter(function (r) {
        var key = type === 'monthly' ? (r.year + '-' + r.month) : r.date;
        if (seen[key]) return false;
        seen[key] = true;
        return true;
      });

      results.sort(function (a, b) {
        if (type === 'monthly') return (a.year * 12 + a.month) - (b.year * 12 + b.month);
        return a.date < b.date ? -1 : 1;
      });

      return results;
    }
  };
})();
